    fn vertex_reasoning_stream_body() -> Vec<u8> {
        let path = std::path::PathBuf::from(env!("CARGO_MANIFEST_DIR"))
            .join("tests")
            .join("fixtures")
            .join("google")
            .join("generative-ai-stream")
            .join("google-thought-signature-reasoning.1.chunks.txt");
        let raw = std::fs::read_to_string(&path)
            .unwrap_or_else(|err| panic!("read vertex reasoning fixture failed: {path:?}: {err}"));

        let mut sse = String::new();
        for line in raw.lines().filter(|line| !line.trim().is_empty()) {
            sse.push_str("data: ");
            sse.push_str(line);
            sse.push_str("\n\n");
        }
        sse.push_str("data: [DONE]\n\n");
        sse.into_bytes()
    }

    fn custom_events_by_type(
        events: &[siumai::prelude::unified::ChatStreamEvent],
        ty: &str,
    ) -> Vec<serde_json::Value> {
        events
            .iter()
            .filter_map(|event| match event {
                siumai::prelude::unified::ChatStreamEvent::Custom { data, .. }
                    if data.get("type") == Some(&serde_json::Value::String(ty.to_string())) =>
                {
                    Some(data.clone())
                }
                _ => None,
            })
            .collect()
    }

    async fn collect_stream_events(
        stream: &mut siumai::prelude::unified::ChatStream,
    ) -> Vec<siumai::prelude::unified::ChatStreamEvent> {
        use futures_util::StreamExt;

        let mut events = Vec::new();
        while let Some(item) = stream.next().await {
            match item {
                Ok(event) => events.push(event),
                Err(err) => panic!("collect vertex public-path stream event failed: {err:?}"),
            }
        }
        events
    }

    fn make_registry(
        transport: Arc<dyn HttpTransport>,
        base_url: &str,
    ) -> siumai::registry::ProviderRegistryHandle {
        let mut providers = std::collections::HashMap::new();
        providers.insert(
            "vertex".to_string(),
            Arc::new(siumai::registry::factories::GoogleVertexProviderFactory)
                as Arc<dyn siumai::prelude::unified::registry::ProviderFactory>,
        );

        let mut provider_build_overrides = std::collections::HashMap::new();
        provider_build_overrides.insert(
            "vertex".to_string(),
            ProviderBuildOverrides::default()
                .with_api_key("test-key")
                .with_base_url(base_url)
                .fetch(transport),
        );

        create_provider_registry(
            providers,
            Some(RegistryOptions {
                separator: ':',
                language_model_middleware: Vec::new(),
                http_interceptors: Vec::new(),
                http_client: None,
                http_transport: None,
                http_config: None,
                api_key: None,
                base_url: None,
                reasoning_enabled: None,
                reasoning_budget: None,
                provider_build_overrides,
                retry_options: None,
                max_cache_entries: None,
                client_ttl: None,
                auto_middleware: true,
            }),
        )
    }

